"use strict";(self.webpackChunkcanada=self.webpackChunkcanada||[]).push([[817],{5410:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"canada_day","metadata":{"permalink":"/canada/blog/canada_day","editUrl":"https://github.com/matteokosina/canada/blob/main/blog/2025-07-05-canada_day.mdx","source":"@site/blog/2025-07-05-canada_day.mdx","title":"Canada Day \ud83c\udde8\ud83c\udde6","description":"<ImageGallery","date":"2025-07-05T00:00:00.000Z","tags":[{"inline":false,"label":"Kanada \ud83c\udde8\ud83c\udde6","permalink":"/canada/blog/tags/canada","description":"Entdecke die Sch\xf6nheit Kanadas mit uns"}],"readingTime":1.32,"hasTruncateMarker":false,"authors":[{"name":"Matteo Kosina","title":"Dualer Student bei SAP","url":"https://github.com/matteokosina","page":{"permalink":"/canada/blog/authors/matteo"},"socials":{"github":"https://github.com/matteokosina","linkedin":"https://www.linkedin.com/in/matteokosina/"},"imageURL":"https://avatars.githubusercontent.com/u/74454734?v=4","key":"matteo"}],"frontMatter":{"slug":"canada_day","title":"Canada Day \ud83c\udde8\ud83c\udde6","authors":"matteo","tags":["canada"]},"unlisted":false,"nextItem":{"title":"Der erste Tag","permalink":"/canada/blog/der_erste_tag"}},"content":"import ImageGallery from \\"../src/components/ui/image-gallery\\";\\n\\n<ImageGallery\\n  images={[\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/IMG_4191.webp\\",\\n      caption: \\"Robben\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/IMG_4199.webp\\",\\n      caption: \\"Der Beaver Lake im Stanley Park\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/IMG_4200.webp\\",\\n      caption: \\"Der Beaver Lake im Stanley Park\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/IMG_4210.webp\\",\\n      caption: \\"Die Skyline von oben\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/IMG_4213.webp\\",\\n      caption: \\"Die Skyline von oben\\",\\n    },\\n  ]}\\n/>\\n\\n> Canada Day, am 1. Juli, ist der kanadische Nationalfeiertag. Er erinnert an die Gr\xfcndung Kanadas durch den British North America Act 1867, als die Provinzen Ontario, Qu\xe9bec, Nova Scotia und New Brunswick zum Dominion of Canada vereint wurden. Urspr\xfcnglich als Dominion Day bekannt, erhielt er 1982 seinen heutigen Namen.\\n\\nDer Feiertag wird landesweit als arbeitsfreier Tag begangen. In Qu\xe9bec f\xe4llt er mit dem \\"Umzugstag\\" zusammen, da viele Mietvertr\xe4ge an diesem Datum enden.\\n\\nWir haben diesen Feiertag genutzt, um unsere neue Umgebung weiter zu erkunden. \ud83c\udf1f Am Vormittag besuchten wir den nahegelegenen Stanley Park, der nur einen kurzen Spaziergang vom Stadtzentrum entfernt liegt. \ud83c\udfde\ufe0f Dort fanden wir eine gr\xfcne Oase mit mehreren Seen, umgeben von der beeindruckenden Skyline der Wolkenkratzer. Besonders faszinierend war der Beaver Lake, wo wir sogar von Bibern angeknabberte B\xe4ume entdeckten. \ud83e\uddab\ud83c\udf33\\nAu\xdferdem konnten wir zwei Robben \ud83e\uddad beobachten (siehe Bilder).\\n\\nAnschlie\xdfend spazierten wir durch das Stadtzentrum, das an jeder Stra\xdfenecke mit Live-Musik, M\xe4rkten und einer lebendigen Atmosph\xe4re punktete. \ud83c\udfb6\ud83d\udecd\ufe0f\\n\\nBevor wir den Tag ausklingen lie\xdfen, besuchten wir noch einen Aussichtspunkt, den wir mit einem Aufzug erreichten. Von dort oben bot sich uns ein atemberaubender Blick auf die Hochh\xe4user und die Stadtlandschaft. \ud83c\udfd9\ufe0f\ud83d\udea1\\n\\nBis bald,  \\nMatteo"},{"id":"der_erste_tag","metadata":{"permalink":"/canada/blog/der_erste_tag","editUrl":"https://github.com/matteokosina/canada/blob/main/blog/2025-06-30-der_erste_tag.mdx","source":"@site/blog/2025-06-30-der_erste_tag.mdx","title":"Der erste Tag","description":"<ImageGallery","date":"2025-06-30T00:00:00.000Z","tags":[{"inline":false,"label":"Kanada \ud83c\udde8\ud83c\udde6","permalink":"/canada/blog/tags/canada","description":"Entdecke die Sch\xf6nheit Kanadas mit uns"}],"readingTime":0.89,"hasTruncateMarker":false,"authors":[{"name":"Matteo Kosina","title":"Dualer Student bei SAP","url":"https://github.com/matteokosina","page":{"permalink":"/canada/blog/authors/matteo"},"socials":{"github":"https://github.com/matteokosina","linkedin":"https://www.linkedin.com/in/matteokosina/"},"imageURL":"https://avatars.githubusercontent.com/u/74454734?v=4","key":"matteo"}],"frontMatter":{"slug":"der_erste_tag","title":"Der erste Tag","authors":"matteo","tags":["canada"]},"unlisted":false,"prevItem":{"title":"Canada Day \ud83c\udde8\ud83c\udde6","permalink":"/canada/blog/canada_day"},"nextItem":{"title":"Anreise","permalink":"/canada/blog/anreise_nach_vancouver"}},"content":"import ImageGallery from \\"../src/components/ui/image-gallery\\";\\n\\n<ImageGallery\\n  images={[\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/hafen_hochhaeuser.webp\\",\\n      caption: \\"Wolkenkratzer am Hafen\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/hafen.webp\\",\\n      caption: \\"Wasserflugzeuge am Hafen\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/marvin_matteo_blueberries.webp\\",\\n      caption: \\"Die ergatterten Blaubeeren\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/steam_clock.webp\\",\\n      caption: \\"Gastown Steam Clock\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/steam_clock2.webp\\",\\n      caption: \\"Gastown Steam Clock\\",\\n    },\\n  ]}\\n/>\\n\\nUnser Tag begann mit einem Spaziergang \xfcber einen Farmers-Market \ud83d\udecd\ufe0f. Dort konnten wir dem Angebot von 2 kg Blaubeeren \ud83e\uded0 nicht widerstehen und mussten sie einfach mitnehmen. Danach machten wir uns auf den Weg ins City Center, wo wir die ber\xfchmte Gastown Steam Clock \u23f0 in Vancouver bewunderten.\\n\\nSp\xe4ter besuchten wir den Hafen, an dem zahlreiche Wasserflugzeuge \u2708\ufe0f starteten und landeten. Nicht weit entfernt ragten die beeindruckenden Wolkenkratzer \ud83c\udfd9\ufe0f in den Himmel. Nachdem wir uns durch die Stra\xdfen Vancouvers treiben lie\xdfen, machten wir uns auf den Heimweg.\\n\\nDen Abend lie\xdfen wir mit einer Joggingrunde \ud83c\udfc3\u200d\u2642\ufe0f ausklingen. Die Landschaft, die von oben so flach aussah, entpuppte sich dabei als \xfcberraschend h\xfcgelig \ud83c\udfde\ufe0f \u2013 eine perfekte Gelegenheit, uns noch einmal richtig auszupowern.\\n\\nBis bald,  \\nMatteo"},{"id":"anreise_nach_vancouver","metadata":{"permalink":"/canada/blog/anreise_nach_vancouver","editUrl":"https://github.com/matteokosina/canada/blob/main/blog/2025-06-29-anreise_nach_vancouver.mdx","source":"@site/blog/2025-06-29-anreise_nach_vancouver.mdx","title":"Anreise","description":"Anreise nach Vancouver \u2708\ufe0f","date":"2025-06-29T00:00:00.000Z","tags":[{"inline":false,"label":"Reise \ud83e\uddf3","permalink":"/canada/blog/tags/travel","description":"Begleite uns auf unserer Reise"}],"readingTime":1.18,"hasTruncateMarker":false,"authors":[{"name":"Matteo Kosina","title":"Dualer Student bei SAP","url":"https://github.com/matteokosina","page":{"permalink":"/canada/blog/authors/matteo"},"socials":{"github":"https://github.com/matteokosina","linkedin":"https://www.linkedin.com/in/matteokosina/"},"imageURL":"https://avatars.githubusercontent.com/u/74454734?v=4","key":"matteo"}],"frontMatter":{"slug":"anreise_nach_vancouver","title":"Anreise","authors":"matteo","tags":["travel"]},"unlisted":false,"prevItem":{"title":"Der erste Tag","permalink":"/canada/blog/der_erste_tag"},"nextItem":{"title":"Bald geht\u2019s los! \ud83c\udde8\ud83c\udde6","permalink":"/canada/blog/intro"}},"content":"## Anreise nach Vancouver \u2708\ufe0f\\n\\nimport ImageGallery from \\"../src/components/ui/image-gallery\\";\\n\\n<ImageGallery\\n  images={[\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/FRA-KEF.webp\\",\\n      caption: \\"Frankfurt -> Reykjavik \u2708\ufe0f\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/KEV-YVR.webp\\",\\n      caption: \\"Reykjavik -> Vancouver \u2708\ufe0f\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/Flug.webp\\",\\n      caption: \\"Frankfurt Flughafen\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/Unterkunft.webp\\",\\n      caption: \\"Unsere Unterkunft (von unten)\\",\\n    },\\n    {\\n      src: \\"https://matteokosina.github.io/canada/media/aufzug.webp\\",\\n      caption: \\"Die Etagen-Auswahl im Aufzug\\",\\n    },\\n  ]}\\n/>\\n\\nAm fr\xfchen Samstagmorgen um 1:20 Uhr begann unsere Reise ins ferne Kanada. Nach einer\\nZugfahrt zum Frankfurter Flughafen startete von dort unser erster Flug nach Reykjavik,\\nIsland. Bei recht k\xfchlen Au\xdfentemperaturen mussten wir nicht lange warten, bis unser\\nAnschlussflug nach Vancouver ging. Nach den ersten drei Stunden Flugzeit lagen nun\\nweitere 7,5 Stunden vor uns.\\n\\nMit wenig Schlaf, aber belohnt durch die beeindruckende Skyline von Vancouver, sind wir schlie\xdflich (inklusive aller Koffer \ud83d\ude0c) am Flughafen angekommen. Von dort aus machten wir uns mit den \\"SkyTrains\\" \u2013 oberirdischen Z\xfcgen, die auf br\xfccken\xe4hnlichen Konstruktionen fahren \u2013 auf den Weg zu unserer Unterkunft. Diese beeindruckte uns sofort mit ihrer Lage: im 26. Stock eines 54-st\xf6ckigen Hochhauses, was uns einen atemberaubenden Blick \xfcber die Silhouette von Vancouver bot. Mehr dazu gibt es in einem kommenden Blog-Beitrag.\\nDerzeit versuchen wir, den Tag durchzuhalten, um uns an die Zeitverschiebung von -9 Stunden zu gew\xf6hnen \ud83d\udecc. Wir freuen uns schon riesig auf die spannenden Tage, die vor uns liegen, und darauf, die Stadt zu erkunden.\\n\\nViele Gr\xfc\xdfe,  \\nMatteo"},{"id":"intro","metadata":{"permalink":"/canada/blog/intro","editUrl":"https://github.com/matteokosina/canada/blob/main/blog/2025-06-07-intro.md","source":"@site/blog/2025-06-07-intro.md","title":"Bald geht\u2019s los! \ud83c\udde8\ud83c\udde6","description":"Hey zusammen! \ud83d\udc4b","date":"2025-06-07T00:00:00.000Z","tags":[{"inline":false,"label":"Reise \ud83e\uddf3","permalink":"/canada/blog/tags/travel","description":"Begleite uns auf unserer Reise"},{"inline":false,"label":"Kanada \ud83c\udde8\ud83c\udde6","permalink":"/canada/blog/tags/canada","description":"Entdecke die Sch\xf6nheit Kanadas mit uns"}],"readingTime":0.31,"hasTruncateMarker":false,"authors":[{"name":"Matteo Kosina","title":"Dualer Student bei SAP","url":"https://github.com/matteokosina","page":{"permalink":"/canada/blog/authors/matteo"},"socials":{"github":"https://github.com/matteokosina","linkedin":"https://www.linkedin.com/in/matteokosina/"},"imageURL":"https://avatars.githubusercontent.com/u/74454734?v=4","key":"matteo"}],"frontMatter":{"slug":"intro","title":"Bald geht\u2019s los! \ud83c\udde8\ud83c\udde6","authors":"matteo","tags":["travel","canada"]},"unlisted":false,"prevItem":{"title":"Anreise","permalink":"/canada/blog/anreise_nach_vancouver"}},"content":"Hey zusammen! \ud83d\udc4b\\n\\nDiesen Sommer startet mein gro\xdfes Abenteuer: Eine Auslandspraxisphase in **Vancouver**! \ud83c\udf0d\u2708\ufe0f  \\nIch kann es kaum erwarten, die atemberaubende Natur, das urbane Flair und die kanadische Gastfreundschaft zu erleben.\\n\\nGerade bin ich dabei, diese Webseite aufzubauen, um meine Erlebnisse mit euch zu teilen. Bleibt gespannt \u2013 hier gibt\u2019s bald Reiseberichte und Fotos! \ud83d\udcf8\ud83c\udfde\ufe0f\\n\\nFreut euch mit mir auf eine unvergessliche Zeit! \ud83d\ude80\\n\\nBis bald!"}]}}')}}]);